    command = args[0]
    if command not in allowed_commands:
        print(f"Command '{command}' is not allowed.")
        return

    # Validate arguments: no null bytes or newlines
    for arg in args[1:]:
        if '\0' in arg or '\n' in arg:
            print("Invalid argument: contains null byte or newline.")
            return

    # Execute commands natively without subprocess
    if command == "pwd":
        print(os.getcwd())
    elif command == "date":
        # Print current date and time in a standard format
        print(datetime.datetime.now().strftime("%a %b %d %H:%M:%S %Z %Y"))
    elif command == "whoami":
        print(getpass.getuser())
    elif command == "echo":
        # Echo the provided arguments
        print(' '.join(args[1:]))
    elif command == "ls":
        # List directory contents; default to current directory
        paths = args[1:] if args[1:] else ['.']
        for path in paths:
            if len(paths) > 1:
                print(f"{path}:")
            try:
                entries = os.listdir(path)
                for entry in sorted(entries):
                    print(entry)
            except FileNotFoundError:
                print(f"ls: cannot access '{path}': No such file or directory")
            except NotADirectoryError:
                print(f"ls: cannot access '{path}': Not a directory")
            except PermissionError:
                print(f"ls: cannot open directory '{path}': Permission denied")
    else:
        # Should never be reached due to whitelist, but kept for safety
        print(f"Command '{command}' not implemented.")

