import hashlib
import hmac

def certificate_matches(certificate, known_hash):
    """
    Return True if the SHA-256 hash of the certificate matches the known_hash.

    The certificate can be a string (encoded to bytes) or bytes.
    The known_hash can be a hex string or bytes.
    """
    # Convert certificate to bytes if it's a string
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    # Compute SHA-256 hash of the certificate
    computed_hash = hashlib.sha256(certificate)

    # Compare based on the type of known_hash
    if isinstance(known_hash, str):
        # Assume known_hash is a hex string
        return hmac.compare_digest(computed_hash.hexdigest(), known_hash)
    elif isinstance(known_hash, bytes):
        return hmac.compare_digest(computed_hash.digest(), known_hash)
    else:
        raise TypeError("known_hash must be str or bytes")

